import SwiftUIstruct EventButton: View {    let title: String    let icon: String    let todaysCount: Int    let action: () -> Void        @State private var isCoolingDown = false    @State private var cooldownProgress: CGFloat = 0.0        let cooldownTime: TimeInterval = 5.0        func startCooldown() {        // First call the LogView action that will edit the state        action()                // Lock the button and reset the circle to full        isCoolingDown = true        cooldownProgress = 1.0                // Animate the circle shrinking to 0        withAnimation(.linear(duration: cooldownTime)) {            cooldownProgress = 0.0        }                // Re-enable the button after the duration        // Note: Using asyncAfter matches the visual animation duration        DispatchQueue.main.asyncAfter(deadline: .now() + cooldownTime) {            isCoolingDown = false        }    }        var body: some View {        Button(action: startCooldown) {            HStack {                Image(systemName: icon)                    .font(.title2)                Text(title)                    .font(.title3)                    .fontWeight(.semibold)                Spacer()                if isCoolingDown {                    ZStack {                        Image(systemName: "checkmark.circle.fill")                            .foregroundStyle(.green)                            .font(.title3)                        Circle()                            .trim(from: 0, to: cooldownProgress)                            .stroke(Color.green, style: StrokeStyle(lineWidth: 2, lineCap: .round))                            // Rotate -90 degrees so the animation starts at 12 o'clock                            .rotationEffect(.degrees(-90))                            // Match frame size + padding for the ring                            .frame(width: 25, height: 25)                            //.foregroundStyle(.green)                    }                }                else if todaysCount > 0 {                    Text("x\(todaysCount)")                }            }            .padding()            .frame(maxWidth: .infinity)            .background(isCoolingDown ? Color.green.opacity(0.2) : Color.purpleAccent.opacity(0.2))            .foregroundStyle(isCoolingDown ? .green : .primary)            .clipShape(RoundedRectangle(cornerRadius: 16))        }        .padding(.horizontal)        .disabled(isCoolingDown)    }}